mapper.select:
SELECT ce.id, cm.name AS giftName, s.name AS studentName, ce.num, ce.credit, ce.verify_state, CASE ce.verify_state WHEN 1 THEN '待审核' WHEN 2 THEN '已通过' WHEN 3 THEN '已拒绝' ELSE '未知' END AS verifyStateDesc, ce.add_time AS addTime, o.name AS schoolName, stf.name AS verifyStaffName, ce.verify_remark AS verifyRemark FROM credit_exchange ce LEFT JOIN credit_mall cm ON ce.credit_mall_id = cm.id LEFT JOIN student s ON ce.student_id = s.id LEFT JOIN org o ON ce.school_id = o.id LEFT JOIN staff stf ON ce.verify_staff = stf.id
ce.deleted = 0
AND cm.name LIKE CONCAT('%', #{condition.giftName}, '%')
AND ce.verify_state = #{condition.verifyState}
AND ce.add_time >= #{condition.startDate}
AND ce.add_time <= #{condition.endDate}
ORDER BY ce.add_time DESC
